class Component {
    public id: string
    public cls: string
    protected visible: bool = true
    protected data: int[]
    private _rendered: bool = false

    constructor(id: string, cls: string, data: int[]) {
        this.id = id
        this.cls = cls
        this.data = data
    }

    isVisible(): bool {
        return this.visible && !this._rendered
    }

    getScore(): int {
        return this.data[0] * this.data[1] - this.data[2]
    }

    render(): string {
        this._rendered = true
        return <div
            id={this.id}
            class={this.cls}
            data-score={this.getScore()}
            data-visible={this.isVisible()}
            data-len={this.data.length}
            data-flag={this.getScore() > 0 && this.visible && !this._rendered}
        >
            <span data-val={this.data[0]}>{this.data[0]}</span>
            <span data-val={this.data[1]}>{this.data[1]}</span>
            <span data-score={this.getScore()}>{this.getScore()}</span>
        </div>
    }
}

class CardComponent extends Component {
    public title: string
    public subtitle: string
    private _highlighted: bool = false
    protected weight: int

    constructor(id: string, cls: string, title: string, subtitle: string, data: int[], weight: int) {
        super(id, cls, data)
        this.title = title
        this.subtitle = subtitle
        this.weight = weight
        this._highlighted = data[0] > weight
    }

    isHighlighted(): bool {
        return this._highlighted && this.isVisible() && this.getScore() > this.weight
    }

    getWeightedScore(): int {
        return this.getScore() * this.weight - this.data[0] * this.weight + this.data[1]
    }

    render(): string {
        val score = this.getWeightedScore()
        val highlighted = this.isHighlighted()
        return <article
            id={this.id}
            class={this.cls}
            data-score={score}
            data-weight={this.weight}
            data-highlighted={highlighted}
            data-visible={this.isVisible()}
            data-flag={highlighted && score > this.weight && !this._highlighted || score < 0 && !highlighted}
            data-chain={this.data[0] * this.weight - this.data[1] * score + this.data[2]}
        >
            <header data-highlighted={highlighted} data-score={score}>
                <h2 data-val={this.weight}>{this.title}</h2>
                <small data-flag={highlighted && !this._highlighted}>{this.subtitle}</small>
            </header>
            <section
                data-score={score}
                data-raw={this.getScore()}
                data-weighted={this.getWeightedScore()}
            >
                <span data-val={this.data[0]} data-gt={this.data[0] > this.weight}>{this.data[0]}</span>
                <span data-val={this.data[1]} data-lt={this.data[1] < score}>{this.data[1]}</span>
                <span data-score={score} data-flag={score > 0 && highlighted}>{score}</span>
            </section>
        </article>
    }
}

class ListComponent extends Component {
    public items: string[]
    public maxItems: int
    private _collapsed: bool = false
    protected threshold: int

    constructor(id: string, cls: string, items: string[], data: int[], maxItems: int, threshold: int) {
        super(id, cls, data)
        this.items = items
        this.maxItems = maxItems
        this.threshold = threshold
        this._collapsed = items.length > maxItems
    }

    isCollapsed(): bool {
        return this._collapsed && this.items.length > this.maxItems && this.isVisible()
    }

    getVisibleCount(): int {
        return this._collapsed && this.maxItems < this.items.length && this.maxItems > 0
    }

    render(): string {
        val score = this.getScore()
        val collapsed = this.isCollapsed()
        val count = this.items.length
        val card0 = new CardComponent(this.id, this.cls, this.items[0], this.items[1], this.data, this.threshold)
        val card1 = new CardComponent(this.id, this.cls, this.items[count - 1], this.items[0], this.data, score)
        return <div
            id={this.id}
            class={this.cls}
            data-count={count}
            data-collapsed={collapsed}
            data-score={score}
            data-threshold={this.threshold}
            data-flag={collapsed && count > this.maxItems && score > this.threshold && !this._collapsed}
            data-chain={count * this.threshold - score * this.maxItems + this.data[0] * count}
        >
            <header data-count={count} data-collapsed={collapsed}>
                <span data-val={count}>Items: {count}</span>
                <span data-flag={collapsed && count > this.maxItems}>
                    Showing: {this.maxItems} of {count}
                </span>
            </header>
            <ul
                data-collapsed={collapsed}
                data-visible={this.getVisibleCount()}
                data-score={score}
            >
                {card0.render()}
                {card1.render()}
                <li data-idx={count - 1} data-last={true}>{this.items[count - 1]}</li>
            </ul>
            <footer
                data-valid={score > this.threshold && !collapsed}
                data-score={score}
                data-flag={score > 0 && count > 0 && !this._collapsed && this.isVisible()}
            >
                <span data-count={count} data-score={score}>
                    {score} / {this.threshold} threshold
                </span>
            </footer>
        </div>
    }
}
